{ title: "कैफ़े में कॉफ़ी ऑर्डर करना", scene: "आप थेसालोनिकी के एक कैफ़े में बैठे हैं। आप कॉफ़ी और पानी ऑर्डर करना चाहते हैं और अंत में बिल माँगते हैं।", lines: [{ who: "them", el: "Καλημέρα, τι θα θέλατε;", hi: "सुप्रभात, आप क्या चाहेंगे?" }, { who: "you", el: "Καλημέρα, έναν καφέ, παρακαλώ.", hi: "सुप्रभात, एक कॉफ़ी, कृपया।" }, { who: "them", el: "Με γάλα ή χωρίς;", hi: "दूध के साथ या बिना?" }, { who: "you", el: "Με γάλα, αλλά χωρίς ζάχαρη.", hi: "दूध के साथ, लेकिन बिना चीनी।" }, { who: "them", el: "Θέλετε και νερό;", hi: "क्या आप पानी भी चाहेंगे?" }, { who: "you", el: "Ναι, ένα νερό, παρακαλώ.", hi: "हाँ, एक पानी, कृपया।" }, { who: "them", el: "Κάτι άλλο;", hi: "कुछ और?" }, { who: "you", el: "Όχι, ευχαριστώ.", hi: "नहीं, धन्यवाद।" }, { who: "them", el: "Ορίστε ο καφές σας.", hi: "यह रही आपकी कॉफ़ी।" }, { who: "you", el: "Ευχαριστώ πολύ.", hi: "बहुत धन्यवाद।" }, { who: "you", el: "Τον λογαριασμό, παρακαλώ.", hi: "बिल, कृपया।" }, { who: "them", el: "Βεβαίως.", hi: "ज़रूर।" }] },
{ title: "होटल में चेक-इन", scene: "आप एथेंस के होटल में पहुँचे हैं। आपके पास आरक्षण है और आप कमरे, पासपोर्ट और लिफ्ट के बारे में पूछते हैं।", lines: [{ who: "them", el: "Καλησπέρα, καλώς ήρθατε.", hi: "शुभ संध्या, आपका स्वागत है।" }, { who: "you", el: "Καλησπέρα, έχω κράτηση.", hi: "शुभ संध्या, मेरा आरक्षण है।" }, { who: "them", el: "Πώς σας λένε;", hi: "आपका नाम क्या है?" }, { who: "you", el: "Με λένε Ραχούλ Σαρμά.", hi: "मेरा नाम राहुल शर्मा है।" }, { who: "them", el: "Το διαβατήριό σας, παρακαλώ.", hi: "आपका पासपोर्ट, कृपया।" }, { who: "you", el: "Ορίστε το διαβατήριό μου.", hi: "यह रहा मेरा पासपोर्ट।" }, { who: "them", el: "Το δωμάτιό σας είναι στον τρίτο όροφο.", hi: "आपका कमरा तीसरी मंज़िल पर है।" }, { who: "you", el: "Πού είναι το ασανσέρ;", hi: "लिफ्ट कहाँ है?" }, { who: "them", el: "Είναι δεξιά.", hi: "यह दाईं ओर है।" }, { who: "you", el: "Ευχαριστώ. Το wifi δουλεύει;", hi: "धन्यवाद। क्या वाई-फ़ाई काम करता है?" }, { who: "them", el: "Ναι, ο κωδικός είναι εδώ.", hi: "हाँ, पासवर्ड यहाँ है।" }, { who: "you", el: "Ευχαριστώ για τη βοήθεια.", hi: "मदद के लिए धन्यवाद।" }] },
{ title: "रास्ता पूछना", scene: "आप एथेंस के प्लाका इलाके में हैं और एक संग्रहालय ढूँढ रहे हैं। आप एक स्थानीय व्यक्ति से रास्ता पूछते हैं।", lines: [{ who: "you", el: "Συγγνώμη, πού είναι το μουσείο;", hi: "माफ़ कीजिए, संग्रहालय कहाँ है?" }, { who: "them", el: "Ποιο μουσείο θέλετε;", hi: "आप कौन सा संग्रहालय चाहते हैं?" }, { who: "you", el: "Θέλω το μουσείο της Ακρόπολης.", hi: "मुझे एक्रोपोलिस संग्रहालय जाना है।" }, { who: "them", el: "Πηγαίνετε ευθεία.", hi: "सीधे जाइए।" }, { who: "you", el: "Μετά;", hi: "फिर?" }, { who: "them", el: "Μετά στρίψτε αριστερά.", hi: "फिर बाएँ मुड़िए।" }, { who: "you", el: "Είναι κοντά;", hi: "क्या यह पास है?" }, { who: "them", el: "Ναι, είναι δέκα λεπτά από εδώ.", hi: "हाँ, यहाँ से दस मिनट है।" }, { who: "you", el: "Μπορείτε να το πείτε πάλι;", hi: "क्या आप इसे फिर से कह सकते हैं?" }, { who: "them", el: "Ευθεία και μετά αριστερά.", hi: "सीधा और फिर बाएँ।" }, { who: "you", el: "Κατάλαβα, ευχαριστώ πολύ.", hi: "समझ गया/गई, बहुत धन्यवाद।" }, { who: "them", el: "Παρακαλώ.", hi: "कोई बात नहीं।" }] },
{ title: "रेस्तरां में रात का खाना", scene: "आप सेंटोरिनी के समुद्र किनारे रेस्तरां में हैं। आप मेज़, मेनू और स्थानीय शाकाहारी विकल्प पूछते हैं।", lines: [{ who: "them", el: "Καλησπέρα, έχετε κράτηση;", hi: "शुभ संध्या, क्या आपका आरक्षण है?" }, { who: "you", el: "Όχι, έχετε τραπέζι για δύο;", hi: "नहीं, क्या आपके पास दो लोगों के लिए मेज़ है?" }, { who: "them", el: "Ναι, παρακαλώ, εδώ.", hi: "हाँ, कृपया, यहाँ।" }, { who: "you", el: "Το μενού, παρακαλώ.", hi: "मेनू, कृपया।" }, { who: "them", el: "Ορίστε το μενού.", hi: "यह रहा मेनू।" }, { who: "you", el: "Έχετε χορτοφαγικό φαγητό;", hi: "क्या आपके पास शाकाहारी खाना है?" }, { who: "them", el: "Ναι, έχουμε σαλάτα και τοπικά πιάτα.", hi: "हाँ, हमारे पास सलाद और स्थानीय डिश हैं।" }, { who: "you", el: "Ποια είναι η σπεσιαλιτέ;", hi: "विशेष डिश कौन सी है?" }, { who: "them", el: "Η σαλάτα με τυρί είναι πολύ καλή.", hi: "चीज़ वाला सलाद बहुत अच्छा है।" }, { who: "you", el: "Θέλω αυτό, χωρίς κρέας.", hi: "मुझे यह चाहिए, बिना मांस।" }, { who: "them", el: "Βεβαίως.", hi: "ज़रूर।" }, { who: "you", el: "Ευχαριστώ πολύ.", hi: "बहुत धन्यवाद।" }] },
{ title: "फेरी टिकट खरीदना", scene: "आप पीरियस बंदरगाह पर हैं और सेंटोरिनी के लिए फेरी टिकट खरीदना चाहते हैं। आप समय, सीट और प्रस्थान के बारे में पूछते हैं।", lines: [{ who: "them", el: "Καλημέρα, πού θέλετε να πάτε;", hi: "सुप्रभात, आप कहाँ जाना चाहते हैं?" }, { who: "you", el: "Θέλω εισιτήριο για τη Σαντορίνη.", hi: "मुझे सेंटोरिनी के लिए टिकट चाहिए।" }, { who: "them", el: "Για σήμερα ή αύριο;", hi: "आज के लिए या कल के लिए?" }, { who: "you", el: "Για σήμερα, παρακαλώ.", hi: "आज के लिए, कृपया।" }, { who: "them", el: "Το πλοίο φεύγει στις τρεις.", hi: "फेरी तीन बजे निकलती है।" }, { who: "you", el: "Υπάρχουν θέσεις;", hi: "क्या सीटें उपलब्ध हैं?" }, { who: "them", el: "Ναι, υπάρχουν.", hi: "हाँ, उपलब्ध हैं।" }, { who: "you", el: "Μία θέση, παρακαλώ.", hi: "एक सीट, कृपया।" }, { who: "them", el: "Θέλετε να πληρώσετε με κάρτα;", hi: "क्या आप कार्ड से भुगतान करना चाहते हैं?" }, { who: "you", el: "Ναι, πληρώνω με κάρτα.", hi: "हाँ, मैं कार्ड से भुगतान करूँगा/करूँगी।" }, { who: "them", el: "Ορίστε το εισιτήριό σας.", hi: "यह रहा आपका टिकट।" }, { who: "you", el: "Ευχαριστώ. Από ποιο λιμάνι φεύγει;", hi: "धन्यवाद। यह किस बंदरगाह से निकलती है?" }] },
{ title: "बाज़ार में खरीदारी", scene: "आप मोनास्तिराकी बाज़ार में एक छोटा उपहार खरीदना चाहते हैं। आप कीमत पूछते हैं, चीज़ देखते हैं और थोड़ा सस्ता विकल्प माँगते हैं।", lines: [{ who: "them", el: "Γεια σας, παρακαλώ.", hi: "नमस्ते, बताइए।" }, { who: "you", el: "Γεια σας, μπορώ να το δω;", hi: "नमस्ते, क्या मैं इसे देख सकता/सकती हूँ?" }, { who: "them", el: "Βεβαίως, ορίστε.", hi: "ज़रूर, यह लीजिए।" }, { who: "you", el: "Πόσο κοστίζει;", hi: "इसकी कीमत कितनी है?" }, { who: "them", el: "Κοστίζει δέκα ευρώ.", hi: "इसकी कीमत दस यूरो है।" }, { who: "you", el: "Είναι λίγο ακριβό.", hi: "यह थोड़ा महँगा है।" }, { who: "them", el: "Έχουμε και κάτι φτηνότερο.", hi: "हमारे पास कुछ सस्ता भी है।" }, { who: "you", el: "Μπορώ να δω εκείνο;", hi: "क्या मैं वह देख सकता/सकती हूँ?" }, { who: "them", el: "Ναι, αυτό κάνει έξι ευρώ.", hi: "हाँ, यह छह यूरो का है।" }, { who: "you", el: "Θέλω αυτό.", hi: "मुझे यह चाहिए।" }, { who: "them", el: "Θέλετε σακούλα;", hi: "क्या आपको थैला चाहिए?" }, { who: "you", el: "Ναι, μια σακούλα, παρακαλώ.", hi: "हाँ, एक थैला, कृपया।" }] },
{ title: "फ़ार्मेसी में मदद माँगना", scene: "आप यात्रा के दौरान सिरदर्द महसूस कर रहे हैं। आप पास की फ़ार्मेसी में जाकर दवा और सलाह माँगते हैं।", lines: [{ who: "them", el: "Καλημέρα, πώς μπορώ να βοηθήσω;", hi: "सुप्रभात, मैं कैसे मदद कर सकता/सकती हूँ?" }, { who: "you", el: "Καλημέρα, έχω πονοκέφαλο.", hi: "सुप्रभात, मुझे सिरदर्द है।" }, { who: "them", el: "Έχετε πυρετό;", hi: "क्या आपको बुखार है?" }, { who: "you", el: "Όχι, δεν έχω πυρετό.", hi: "नहीं, मुझे बुखार नहीं है।" }, { who: "them", el: "Έχετε αλλεργία σε φάρμακα;", hi: "क्या आपको दवाओं से एलर्जी है?" }, { who: "you", el: "Όχι, δεν έχω αλλεργία.", hi: "नहीं, मुझे एलर्जी नहीं है।" }, { who: "them", el: "Αυτό το φάρμακο είναι για πονοκέφαλο.", hi: "यह दवा सिरदर्द के लिए है।" }, { who: "you", el: "Πώς το παίρνω;", hi: "मैं इसे कैसे लूँ?" }, { who: "them", el: "Με νερό, μετά το φαγητό.", hi: "पानी के साथ, खाने के बाद।" }, { who: "you", el: "Ευχαριστώ. Πόσο κοστίζει;", hi: "धन्यवाद। इसकी कीमत कितनी है?" }, { who: "them", el: "Κάνει τέσσερα ευρώ.", hi: "यह चार यूरो का है।" }, { who: "you", el: "Πληρώνω με κάρτα.", hi: "मैं कार्ड से भुगतान करूँगा/करूँगी।" }] },
{ title: "स्थानीय व्यक्ति से छोटी बातचीत", scene: "आप क्रेट के एक शांत कैफ़े में बैठे हैं और पास बैठे स्थानीय व्यक्ति से बातचीत शुरू करते हैं। आप बताते हैं कि आप भारत से हैं और ग्रीस आपको पसंद है।", lines: [{ who: "you", el: "Γεια σας, μιλάω λίγο ελληνικά.", hi: "नमस्ते, मैं थोड़ी ग्रीक बोलता/बोलती हूँ।" }, { who: "them", el: "Μπράβο, από πού είστε;", hi: "बहुत अच्छा, आप कहाँ से हैं?" }, { who: "you", el: "Είμαι από την Ινδία.", hi: "मैं भारत से हूँ।" }, { who: "them", el: "Καλώς ήρθατε στην Ελλάδα.", hi: "ग्रीस में आपका स्वागत है।" }, { who: "you", el: "Ευχαριστώ, μου αρέσει πολύ η Ελλάδα.", hi: "धन्यवाद, मुझे ग्रीस बहुत पसंद है।" }, { who: "them", el: "Ποια πόλη σας αρέσει;", hi: "आपको कौन सा शहर पसंद है?" }, { who: "you", el: "Μου αρέσει η Αθήνα και η Θεσσαλονίκη.", hi: "मुझे एथेंस और थेसालोनिकी पसंद हैं।" }, { who: "them", el: "Και η Κρήτη;", hi: "और क्रेट?" }, { who: "you", el: "Η Κρήτη είναι πολύ όμορφη.", hi: "क्रेट बहुत सुंदर है।" }, { who: "them", el: "Σας αρέσει το φαγητό;", hi: "क्या आपको खाना पसंद है?" }, { who: "you", el: "Ναι, το φαγητό είναι νόστιμο.", hi: "हाँ, खाना स्वादिष्ट है।" }, { who: "them", el: "Χάρηκα πολύ.", hi: "मिलकर बहुत खुशी हुई।" }] }
